function verifyJWT(token, secret) {
  if (!secret) throw new Error('CONFIGURACAO: N8N_JWT_SECRET nao definida');
  if (!token || typeof token !== 'string') throw new Error('AUTH_MISSING');
  const clean = token.startsWith('Bearer ') ? token.slice(7) : token;
  const parts = clean.split('.');
  if (parts.length !== 3) throw new Error('AUTH_INVALID');
  const [header, payload, signature] = parts;
  const expected = PURE_CRYPTO.hmacSha256(secret, header + '.' + payload);
  if (signature !== expected) throw new Error('AUTH_INVALID');
  const decoded = JSON.parse(Buffer.from(payload, 'base64url').toString());
  if (decoded.exp && decoded.exp < Math.floor(Date.now() / 1000)) {
    throw new Error('AUTH_EXPIRED');
