const checkingData = $items('BigQuery - Auditoria Aprovacao')[0].json || {};
const webhookData = $items('Webhook POST1')[0].json.body || {};

const emailDestino = (checkingData.email_contato || webhookData.email_contato || '').trim();
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailDestino || !emailRegex.test(emailDestino)) {
  return [{ json: { emailHtml: null, emailInvalido: true, emailDestino: '', motivo: 'email_contato ausente ou invalido' } }];
}

const nPi = checkingData.n_pi || webhookData.id || 'N/A';
const cliente = checkingData.cliente || webhookData.cliente || '';
const veiculo = checkingData.veiculo || webhookData.veiculo || '';
const meio = checkingData.meio || webhookData.meio || '';
const approvedBy = webhookData.approval_user || 'Sistema';
const approvedAt = new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });

const html = `<!DOCTYPE html>
<html><head><meta charset="utf-8"></head>
<body style="font-family: 'Segoe UI', Arial, sans-serif; background: #f4f4f7; margin: 0; padding: 32px;">
<div style="max-width: 600px; margin: 0 auto; background: #fff; border-radius: 12px; overflow: hidden; box-shadow: 0 2px 12px rgba(0,0,0,0.08);">
  <div style="background: linear-gradient(135deg, #10b981, #059669); padding: 28px 32px; text-align: center;">
    <h1 style="color: #fff; margin: 0; font-size: 22px;">&#10003; Checking Aprovado</h1>
    <p style="color: rgba(255,255,255,0.85); margin: 8px 0 0; font-size: 14px;">PI ${nPi} - ${cliente}</p>
  </div>
  <div style="padding: 28px 32px;">
    <p style="font-size: 15px; color: #333; margin: 0 0 18px;">O checking abaixo foi <strong style="color: #10b981;">aprovado</strong> com sucesso.</p>
    <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
      <tr><td style="padding: 10px 0; border-bottom: 1px solid #eee; color: #666;">PI</td><td style="padding: 10px 0; border-bottom: 1px solid #eee; font-weight: 600;">${nPi}</td></tr>
      <tr><td style="padding: 10px 0; border-bottom: 1px solid #eee; color: #666;">Cliente</td><td style="padding: 10px 0; border-bottom: 1px solid #eee; font-weight: 600;">${cliente}</td></tr>
      <tr><td style="padding: 10px 0; border-bottom: 1px solid #eee; color: #666;">Veiculo</td><td style="padding: 10px 0; border-bottom: 1px solid #eee; font-weight: 600;">${veiculo}</td></tr>
      <tr><td style="padding: 10px 0; border-bottom: 1px solid #eee; color: #666;">Meio</td><td style="padding: 10px 0; border-bottom: 1px solid #eee; font-weight: 600;">${meio}</td></tr>
      <tr><td style="padding: 10px 0; border-bottom: 1px solid #eee; color: #666;">Aprovado por</td><td style="padding: 10px 0; border-bottom: 1px solid #eee; font-weight: 600;">${approvedBy}</td></tr>
      <tr><td style="padding: 10px 0; color: #666;">Data</td><td style="padding: 10px 0; font-weight: 600;">${approvedAt}</td></tr>
    </table>
  </div>
  <div style="background: #f9fafb; padding: 16px 32px; text-align: center; font-size: 12px; color: #999;">
    Grupo OM - Painel de Checking
  </div>
</div>
</body></html>`;

return [{ json: { emailHtml: html, emailDestino, emailInvalido: false, nPi, cliente } }];
